class DataCompression{static compress(e){try{const t=JSON.stringify(e),r=t.replace(/\s+/g,"").replace(/"/g,'"'),s=btoa(r);return{data:s,original:t.length,compressed:s.length,ratio:(100*(1-s.length/t.length)).toFixed(2)}}catch(e){return console.error("[DataCompression] Compress error:",e),null}}static decompress(e){try{if("string"==typeof e){const t=atob(e);return JSON.parse(t)}if(e.data){const t=atob(e.data);return JSON.parse(t)}return null}catch(e){return console.error("[DataCompression] Decompress error:",e),null}}static async storeCompressed(e,t){try{const r=this.compress(t);if(!r)return!1;const s=await caches.open("compressed-v1"),o=new Response(JSON.stringify(r),{headers:{"Content-Type":"application/json"}});return await s.put(e,o),console.log(`[DataCompression] Stored ${e} - Ratio: ${r.ratio}%`),!0}catch(e){return console.error("[DataCompression] Store error:",e),!1}}static async getCompressed(e){try{const t=await caches.open("compressed-v1"),r=await t.match(e);if(!r)return null;const s=await r.json();return this.decompress(s)}catch(e){return console.error("[DataCompression] Get error:",e),null}}static getCompressionRatio(e,t){return 0===e?"0.00":(100*(1-t/e)).toFixed(2)}static compressMultiple(e){const t={};return Object.keys(e).forEach(r=>{const s=this.compress(e[r]);s&&(t[r]=s)}),t}static decompressMultiple(e){const t={};return Object.keys(e).forEach(r=>{const s=this.decompress(e[r]);s&&(t[r]=s)}),t}static async getCacheStats(){try{const e=await caches.open("compressed-v1"),t=await e.keys();let r=0,s=0;for(const o of t){const t=await e.match(o);if(t){const e=await t.json();e.original&&e.compressed&&(r+=e.original,s+=e.compressed)}}return{itemCount:t.length,totalOriginal:r,totalCompressed:s,totalRatio:this.getCompressionRatio(r,s)}}catch(e){return console.error("[DataCompression] Get stats error:",e),null}}static async clearCache(){try{return await caches.delete("compressed-v1"),console.log("[DataCompression] Cache cleared"),!0}catch(e){return console.error("[DataCompression] Clear error:",e),!1}}}"undefined"!=typeof window&&(window.DataCompression=DataCompression,console.log("[DataCompression] ✅ Initialized"));